// Absolute Score Calculation
// Weights: nq200ma(30%), nq50ma(30%), nq20ema50ema(20%), mtf(10%), market_phase(10%)

const weights = {
    nq200ma: 0.30,
    nq50ma: 0.30,
    nq20ema50ema: 0.20,
    mtf: 0.10,
    market_phase: 0.10
};

// Default scores if no data (neutral = 50)
let nq200maScore = 50;
let nq50maScore = 50;
let nq20ema50emaScore = 50;
let mtfScore = 50;
let marketPhaseScore = 50;

if (msg.payload && msg.payload.length > 0) {
    const data = msg.payload[0];

    // Calculate NQ200MA score (price vs 200MA)
    // Score = 100 if price > 200MA, 0 if price < 200MA * 0.9, linear between
    if (data.price && data.ma200) {
        const ratio = data.price / data.ma200;
        nq200maScore = Math.min(100, Math.max(0, (ratio - 0.9) * 1000));
    }

    // Calculate NQ50MA score
    if (data.price && data.ma50) {
        const ratio = data.price / data.ma50;
        nq50maScore = Math.min(100, Math.max(0, (ratio - 0.9) * 1000));
    }

    // Calculate NQ20EMA vs NQ50EMA score
    if (data.ema20 && data.ema50) {
        nq20ema50emaScore = data.ema20 > data.ema50 ? 100 : 0;
    }

    // MTF score from data
    if (data.mtf_score !== undefined) {
        mtfScore = data.mtf_score;
    }

    // Market phase score
    if (data.market_phase !== undefined) {
        const phaseScores = { accumulation: 100, markup: 80, distribution: 20, markdown: 0 };
        marketPhaseScore = phaseScores[data.market_phase] || 50;
    }
}

// Calculate final weighted score
const finalScore = Math.round(
    nq200maScore * weights.nq200ma +
    nq50maScore * weights.nq50ma +
    nq20ema50emaScore * weights.nq20ema50ema +
    mtfScore * weights.mtf +
    marketPhaseScore * weights.market_phase
);

// Determine trend direction
let trendDirection = 'sideways';
if (finalScore >= 80) trendDirection = 'strong_bull';
else if (finalScore >= 60) trendDirection = 'bull';
else if (finalScore >= 40) trendDirection = 'weak';
else if (finalScore >= 20) trendDirection = 'bear';
else trendDirection = 'strong_bear';

msg.payload = {
    nq200ma_score: Math.round(nq200maScore),
    nq50ma_score: Math.round(nq50maScore),
    nq20ema50ema_score: Math.round(nq20ema50emaScore),
    mtf_score: Math.round(mtfScore),
    market_phase_score: Math.round(marketPhaseScore),
    final_absolute_score: finalScore,
    trend_direction: trendDirection,
    timestamp: new Date()
};

return msg;
